-- Lote 5: Convite, Devoção, Consagração
INSERT INTO ai_knowledge_base (category, topic, core_teaching, bible_references, summary, keywords) VALUES

('Doutrina Católica', 'Devoção aos Santos e Consagração a Maria',
'Santos de devoção: amizade espiritual e imitação de virtudes de um santo, pedindo intercessão junto a Deus. "Lembrai-vos dos vossos líderes e imitai a sua fé" (Hb 13:7). "Sede meus imitadores como eu sou de Cristo" (1Cor 11:1). Os primeiros cristãos celebravam Eucaristia sobre túmulos de mártires e pediam intercessão. Consagração a Maria: entregar-se a Jesus pelas mãos de Maria, confiando na intercessão e exemplo de obediência perfeita. Maria se consagrou totalmente: "Eis a serva do Senhor" (Lc 1:38). Em Caná, leva os servos a obedecer Cristo: "Fazei tudo o que Ele vos disser" (Jo 2:5). Maria como Advogada: intercessora junto ao Rei, como a rainha-mãe Betsabé (1Rs 2:19). A intercessão dos santos não concorre com Cristo — é subordinada e dependente da mediação única de Cristo (1Tm 2:5).',
ARRAY['Hb 13:7','1Cor 11:1','Tg 5:16','Lc 1:38','Lc 1:48','Jo 19:26-27','Jo 2:1-11','1Rs 2:19-20','1Tm 2:5','1Tm 2:1','Rm 15:30','Ef 4:4','1Cor 12:25-27'],
'Devoção aos santos é imitação e pedido de intercessão. Consagração a Maria é entregar-se a Jesus pelas mãos dela. Tudo aponta para Cristo.',
ARRAY['devoção','santos','consagração','maria','intercessão','advogada','rainha-mãe']),

('Escritura e Tradição', 'Coisas Não Escritas na Bíblia que Cristãos Aceitam',
'O argumento "não está na Bíblia" ignora que a própria fé cristã contém verdades e práticas não escritas explicitamente. A Bíblia nunca ensinou que só o que está nela é válido. Exemplos: o cânon bíblico (lista dos livros) não está na Bíblia — foi definido pela Igreja. O culto no domingo é prática apostólica, não mandamento escrito. A Trindade como termo não aparece na Bíblia. A Sola Scriptura ("somente a Bíblia") nunca foi ensinada na Bíblia. O formato do culto evangélico, dízimo como obrigação no NT, pastor como único líder, batismo só de adultos — nada disso tem mandamento explícito. Se o critério é "estar escrito", então muitas práticas aceitas por todos os cristãos falham nesse teste.',
ARRAY['Jo 21:25','2Ts 2:15','1Cor 11:2','At 20:7','Ap 1:10','At 20:35'],
'Muitas verdades cristãs aceitas por todos não estão explícitas na Bíblia: cânon, Trindade, culto dominical, etc. Escritura e Tradição se completam.',
ARRAY['sola scriptura','tradição','cânon','trindade','domingo','bíblia','práticas cristãs']),

('Fundamentos', 'Convite ao Estudo da Fé Católica',
'A fé católica é um convite ao estudo sério, honesto e fundamentado da tradição cristã mais antiga. A Igreja Católica preserva a continuidade com os apóstolos, a Escritura e a Tradição como fontes inseparáveis da Revelação. O estudo abrange: compreensão da Bíblia (métodos, chaves de leitura), relação Escritura-Tradição, autoridade e unidade da Igreja, práticas da Igreja primitiva, história real da Igreja (erros e frutos), doutrina plena (sacramentos, Maria, comunhão dos santos), e discernimento de práticas erradas (prosperidade, emocionalismo, superstição). O objetivo não é atacar, mas apresentar a verdade da fé com base bíblica, histórica e lógica.',
ARRAY['At 2:42','1Tm 3:15','Mt 16:18','Jo 17:21'],
'Convite ao estudo fundamentado da fé católica: bíblico, histórico e lógico. Uma jornada de descoberta da tradição cristã mais antiga.',
ARRAY['convite','estudo','fé católica','aprendizado','catequese','apologética','fundamentos']);
